import { isNumber } from 'lodash-es';
import { Fragment, useMemo } from 'react';

import { legendMarkersSvg } from './RangeLegendMarkers.sty.js';
import { ORIENTATION } from '../../../../../constants.js';
import { LABEL_ALIGNMENT } from '../../constants.js';
import { useOrientation } from '../../context/RangeLegendOrientationContext.js';
import { useScale } from '../../context/RangeLegendScaleContext.js';
import { useLegendFormattedLabels } from '../../hooks/use-legend-formatted-labels.js';
import type { InternalRangeItem } from '../../types/range-legend.internal.js';
import { getLabelAlignment } from '../../utils/get-label-alignment.js';
import { getLabelEndPosition } from '../../utils/get-label-end-position.js';
import { getMarkers } from '../../utils/get-markers.js';
import { RangeLegendBoundaryLabels } from '../RangeLegendBoundaryLabels.js';
import { RangeLegendItemLabel } from '../RangeLegendItemLabel/RangeLegendItemLabel.js';
import { RangeLegendItemMarker } from '../RangeLegendItemMarker/RangeLegendItemMarker.js';
import { RangeLegendSegmentsOverlay } from '../RangeLegendSegmentsOverlay.js';

interface RangeLegendMarkersProps {
  items: InternalRangeItem[];
  maxValue?: number;
  minValue?: number;
}

export const RangeLegendMarkers = (props: RangeLegendMarkersProps) => {
  const { items, maxValue, minValue } = props;
  const hasMinValue = isNumber(minValue);
  const hasMaxValue = isNumber(maxValue);

  const { orientation } = useOrientation();
  const { scale } = useScale();
  const [rangeStartPosition, rangeEndPosition] = scale.range();

  const isVertical = orientation === ORIENTATION.Vertical;

  const { itemMarkers, singlePointRangeMarkers } = useMemo(
    () => getMarkers(items, isVertical),
    [isVertical, items],
  );

  const internalRangeItems = useLegendFormattedLabels(items);

  const addedMarkers = new Set<number>([]);
  const markerLabel = isVertical
    ? `Labels from ${Array.from(itemMarkers)[itemMarkers.size - 1]} to ${
        Array.from(itemMarkers)[0]
      }`
    : `Labels from ${Array.from(itemMarkers)[0]} to ${
        Array.from(itemMarkers)[itemMarkers.size - 1]
      }`;

  return (
    <svg
      className={legendMarkersSvg({
        isHorizontal: orientation === ORIENTATION.Horizontal,
      })}
      role="group"
      aria-label="Chart legend"
    >
      <g role="list" aria-label={markerLabel}>
        {/* LABELS */}
        {internalRangeItems.map((item) => {
          const hasFromLabel =
            itemMarkers.has(item.from) && !addedMarkers.has(item.from);
          const hasToLabel =
            itemMarkers.has(item.to) && !addedMarkers.has(item.to);

          if (!hasFromLabel && !hasToLabel) {
            return null;
          }

          addedMarkers.add(item.from);
          addedMarkers.add(item.to);

          const startPosition = scale(item.from);
          const endPosition = scale(item.to);
          const isSinglePointRange = startPosition === endPosition;

          const hasSameStartPosition = isVertical
            ? startPosition === rangeEndPosition
            : startPosition === rangeStartPosition;
          const isFirstItem = hasSameStartPosition && !hasMinValue;

          const hasSameEndPosition = isVertical
            ? endPosition === rangeStartPosition
            : endPosition === rangeEndPosition;
          const isLastItem = hasSameEndPosition && !hasMaxValue;

          const labelAlignment = getLabelAlignment(
            hasMaxValue,
            isLastItem,
            isVertical,
          );

          const labelEndPosition = getLabelEndPosition(
            endPosition,
            isSinglePointRange,
            isLastItem,
          );

          return (
            <Fragment key={`label-'${item.from}`}>
              {hasFromLabel && (
                <RangeLegendItemLabel
                  labelId={item.from}
                  startPosition={startPosition}
                  endPosition={startPosition}
                  text={item.labels.from}
                  alignment={
                    hasMinValue || !isFirstItem
                      ? LABEL_ALIGNMENT.Center
                      : LABEL_ALIGNMENT.End
                  }
                />
              )}
              {hasToLabel && !isSinglePointRange && (
                <RangeLegendItemLabel
                  labelId={item.to}
                  startPosition={labelEndPosition}
                  endPosition={labelEndPosition}
                  text={item.labels.to}
                  alignment={labelAlignment}
                />
              )}
            </Fragment>
          );
        })}

        {/* ARROWS */}
        {Array.from(itemMarkers).map((marker) => {
          const position = scale(marker);

          return (
            <RangeLegendItemMarker
              key={`marker-'${marker}`}
              position={position}
              markerValue={marker}
              isReversed={isVertical}
              isSinglePointRange={singlePointRangeMarkers.has(marker)}
            />
          );
        })}
        <RangeLegendBoundaryLabels
          items={internalRangeItems}
          maxValue={maxValue}
          minValue={minValue}
        />
      </g>

      <RangeLegendSegmentsOverlay itemMarkers={Array.from(itemMarkers)} />
    </svg>
  );
};
